module top_module(
  input clk_in,
  input reset,
  output reg clk_out
);parameter N = 2; // division factor

reg [N-1:0] inv_counter;

always @(posedge clk_in or posedge reset) begin
  if (reset) begin
    clk_out <= 1'b0;
    inv_counter <= 0;
  end else begin
    if (inv_counter == N-1) begin
      clk_out <= ~clk_out;
      inv_counter <= 0;
    end else begin
      inv_counter <= inv_counter + 1;
    end
  end
end

endmodule
